1	export type Cell = [number, number];
2	
3	const NEIGHBOR_OFFSETS: ReadonlyArray<[number, number]> = [
4	  [-1, -1], [-1, 0], [-1, 1],
5	  [ 0, -1],          [ 0, 1],
6	  [ 1, -1], [ 1, 0], [ 1, 1],
7	];
8	
9	const cellKey = ([x, y]: Cell): string => `${x},${y}`;
10	
11	const neighborsOf = ([x, y]: Cell): Cell[] =>
12	  NEIGHBOR_OFFSETS.map(([dx, dy]) => [x + dx, y + dy]);
13	
14	const survives = (isAlive: boolean, liveNeighbors: number): boolean =>
15	  liveNeighbors === 3 || (isAlive && liveNeighbors === 2);
16	
17	export function nextGeneration(cells: Cell[]): Cell[] {
18	  const alive = new Set(cells.map(cellKey));
19	
20	  const candidates = new Map<string, Cell>();
21	  for (const cell of cells) {
22	    candidates.set(cellKey(cell), cell);
23	    for (const neighbor of neighborsOf(cell)) {
24	      candidates.set(cellKey(neighbor), neighbor);
25	    }
26	  }
27	
28	  return [...candidates.values()].filter(cell => {
29	    const liveNeighbors = neighborsOf(cell).filter(n => alive.has(cellKey(n))).length;
30	    return survives(alive.has(cellKey(cell)), liveNeighbors);
31	  });
32	}
33

1	import { describe, it, expect } from "vitest";
2	import { nextGeneration } from "./game-of-life.js";
3	
4	describe("Game of Life - nextGeneration", () => {
5	  it("should return empty array when given empty array", () => {
6	    expect(nextGeneration([])).toEqual([]);
7	  });
8	  it("should kill a single live cell (underpopulation)", () => {
9	    expect(nextGeneration([[0, 0]])).toEqual([]);
10	  });
11	  it("should keep a block (still life) unchanged", () => {
12	    const block: [number, number][] = [[0, 0], [1, 0], [0, 1], [1, 1]];
13	    const result = nextGeneration(block);
14	    expect(result).toHaveLength(4);
15	    expect(new Set(result.map(c => `${c[0]},${c[1]}`)))
16	      .toEqual(new Set(block.map(c => `${c[0]},${c[1]}`)));
17	  });
18	  it("should oscillate a vertical blinker to horizontal", () => {
19	    const vertical: [number, number][] = [[0, 0], [0, 1], [0, 2]];
20	    const result = nextGeneration(vertical);
21	    expect(result).toHaveLength(3);
22	    expect(new Set(result.map(c => `${c[0]},${c[1]}`)))
23	      .toEqual(new Set(["-1,1", "0,1", "1,1"]));
24	  });
25	  it("should birth a dead cell with exactly 3 live neighbors", () => {
26	    const input: [number, number][] = [[0, 0], [1, 0], [0, 1]];
27	    const result = nextGeneration(input);
28	    expect(new Set(result.map(c => `${c[0]},${c[1]}`)))
29	      .toEqual(new Set(["0,0", "1,0", "0,1", "1,1"]));
30	  });
31	  it.todo("should handle negative coordinates");
32	});
