const countLiveNeighbors = (cell: Cell, alive: Set<string>): number =>
  neighborsOf(cell).filter(n => alive.has(cellKey(n))).length;

export function nextGeneration(cells: Cell[]): Cell[] {
  const alive = new Set(cells.map(cellKey));

  const candidates = new Map<string, Cell>();
  for (const cell of cells) {
    candidates.set(cellKey(cell), cell);
    for (const neighbor of neighborsOf(cell)) {
      candidates.set(cellKey(neighbor), neighbor);
    }
  }

  return [...candidates.values()].filter(cell =>
    survives(alive.has(cellKey(cell)), countLiveNeighbors(cell, alive))
  );
}

